const Q_ECONOMICS_2010=[{"id": "objective>Economics>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject is this? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is indicated in the id of the question. The id is 'objective>Economics>2010>1', which means the subject is Economics.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economics is the study of human behaviour as it relates to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efficient allocation of resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">operation of companies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">generation of income</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economics is a social science that studies how individuals, governments, firms, and nations make choices on allocating scarce resources to satisfy their unlimited wants. Hence, the correct answer is 'efficient allocation of resources'.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The downturn in the prices of shares on stock market is a highlight of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efficient allocation of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the invisible hand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the regulatory nature of the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer rationality</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The downturn in the prices of shares on the stock market is a highlight of the regulatory nature of the market. This is because the stock market is a regulated environment where the forces of demand and supply determine the prices of shares. When there is a downturn in prices, it indicates that the market is self-regulating, adjusting to changes in economic conditions.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If X<span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span> = 6 and N = 6, determine the value of ∑FX. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">36 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">72.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The given equation is X<span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span> = 6 and N = 6. This implies that the sum of the product of the frequency (F) and the corresponding value (X) is 6, and the total number of values (N) is also 6. Therefore, the sum of these products (∑FX) is equal to 6*6 = 36.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The standard deviation of a set of data is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">always measured from the mode  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the most representative of averages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">always measured from the median  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a measure of dispersion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standard deviation is one of measures of dispersion others include mean deviation, range and variance.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mean is the best measure of central tendency because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is not affected by extreme values in a data  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a midpoint value in an array of data </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is balancing point in an observation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be calculated from incomplete data.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mean, or average, is calculated by adding up all the values in a dataset and dividing by the number of values. It can be calculated even when data is missing or incomplete. Other measures of central tendency, like the median and mode, may be affected by the presence of extreme values or the arrangement of data, but the mean can still be computed with incomplete data, which makes it a versatile and widely used measure of central tendency.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most popular sizes of dresses and shoes are determined by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">range </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mean  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">median</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most popular sizes of dresses and shoes are determined by the mode. In statistics, the mode is the value that appears most frequently in a data set. In this context, the mode would represent the most common or popular sizes of dresses and shoes.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> If the demand for a good is more elastic than its supply, the tax burden is borne </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> equally by consumers and producers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more by producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more by consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more by retailers and producers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When elasticity of demand for a good is more elastic than its supply, the burden must be borne by the producer otherwise, there will be loss in revenue as the consumer may respond greatly to price increases due to tax.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of a commodity with elastic demand increases, the revenue accruing to the producer will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">double</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a good has elasticity demand, an increase in its price will lead to greater decrease in quantity demanded. This will lead to loss of revenue by the producer.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> An excess demand for beans will result from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> an increase in the price of beans  </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> an increase in the supply of beans </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a decrease in the price of beans</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a decrease in the supply of beans</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excess demand is a situation where the quantity demanded for a good or service exceeds its supply in a market. It can occur at the current market price or when demand is not equal to supply. This usually happens when the price of a good or service is set below the equilibrium price, such that the quantity demanded is greater than the quantity supplied. Therefore, an excess demand for beans will result from a decrease in the supply of beans.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer surplus tends to be higher when demand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitarily elastic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer surplus is the difference between the total amount that consumers are willing and able to pay for a good or service (indicated by the demand curve) and the total amount that they actually do pay (i.e. the market price). Consumer surplus is higher when demand is elastic because when price decreases, the quantity demanded increases more than proportionally, thus increasing the consumer surplus. Elastic demand means that demand is sensitive to changes in price.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER SURPLUS"}, {"id": "objective>Economics>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the assumptions of ordinal utility theory is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">choice is not consistent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility can be ranked </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility is a function of price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">satisfaction is measurable.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinal utility states that utility cannot be measured objectively. Rather, consumer can only rank their preference between combinations of two goods.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility explains why </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the slope of a normal demand curve is negative </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an abnormal demand curve slopes upwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the slope of a normal demand curve is positive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the consumption of inferior goods increases with income.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility has been used to derive the law of demand which explains the negative slope of a normal demand curve.The law of diminishing is used to explain the law of demand.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a consumer plans to spend 120k on four oranges but spent 80k, his consumer surplus is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦1.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦0.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2.00</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between what a consumer is planning to spend and the amount he actually spent on it constitute consumer surplus i.e.,  <br/> 120 - 80 = 40K <br/> 40k to nairia = 40/100 <br/>                = 0.40</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER SURPLUS"}, {"id": "objective>Economics>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A set of factors that can shift the supply curve are changes in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weather, price and technology  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology, weather and population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology, price and taste  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">population, price and taste</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in supply curve can only occur when factors affecting supply other than the price changes. The supply curve can shift due to technology, weather, population, government policy etc.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the coefficient of price elasticity of supply is greater than one, the supply is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinitely inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly elastic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supply curve is said to be elastic if the coefficient of price elasticity of supply is greater than 1.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If commodity X is a by-product of commodity Y, this implies that both commodities are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> in competitive supply  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in composite supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">jointly supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in excess supply</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commodity X and Y are jointly supplied if X is a by-product of Y. This is because the production of one commodity (Y) leads to the production of another commodity (X). Joint supply is a term used in economics to describe a situation where the supply of one good is linked to the supply of another good. For example, in the meat industry, an increase in the supply of beef may lead to an increase in the supply of leather, as leather is a by-product of beef production.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In perfect competition, price is determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buyers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In perfect competition, price is determined by the interaction of demand and supply forces and these are referred to as market forces.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to reduce hardship faced by consumers due to high prices, government can introduce</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maximum prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodity boards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum prices </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price control boards</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maximum price is used in order to peg down and limit the extent at which price can be rise. This is price ceiling.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Average product is less than marginal product when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is constant returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is increasing returns to scale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is decreasing returns to scale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns set in.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average product is the output per unit of input, while the marginal product is the additional output from using one more unit of input. When there is increasing returns to scale, each additional unit of input produces more output than the previous unit. This means that the marginal product (additional output from the last unit of input) is greater than the average product (total output divided by total input). Therefore, the average product is less than the marginal product when there is increasing returns to scale.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm enjoying economies of scale is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reducing average cost as production increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">benefiting from the activities of other firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximizing profits as production increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">having an upward-sloping average cost curve.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economics of scale occurs when a firm experiences decrease in per unit cost (average variable cost) as it expands its product on large scale.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> The rising portion of the long-run average cost curve of a firm is an indication that it is experiencing</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing efficiency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">economies of scale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diseconomies of scale   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing marginal returns.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A diseconomies of scale occurs when as a result of increasing output firm is incurring higher per-unit cost. The rising portion of the LRAC is due to diseconomies of scale while the falling portion is due to economies of scale.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An industry's supply curve is more likely to be elastic when firms are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enjoying free entry and exit  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">operating at full capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">operating below capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximizing profits.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factor mobility: when moving resources into the industry is easier, the supply curve in more elastic. .</div>", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE"}, {"id": "objective>Economics>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of monopolistic competition is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is mobility of factors of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no single seller dominates the market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers have perfect knowledge of price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the firms are price-takers.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a monopolistic market there is no single seller that dominates the market. Other characteristics are: no large number of buyers or sellers, there is free entry and exit etc.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve for factors of production </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is perfectly elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">slopes upwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slopes downwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is perfectly inelastic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand for factor of production is a derived demand and its slope downward just as normal demand curve.</div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An agreement among firms on price and segmentation is termed </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cartel  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">collusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">haggling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Collusion is a situation in which firms in an oligopolistic industry tacitly decide to set the same price as the price leader for the industry. <br/>  <br/> An agreement among firms on price and segmentation is often referred to as \"Collusion\" or a \"Collusive Agreement.\"</div>", "topic": "MARKET STRUCTURE : OLIGOPOLY"}, {"id": "objective>Economics>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In national income accounting, tax is determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">level of income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of investment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of savings</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Level of income is used to determine tax and more so consumption, savings and investment depends on income. The higher the income, the higher the tax rate.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in aggregate spending in an economy will ultimately lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boom  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recession</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in aggregate spending in an economy will ultimately lead to a recession. Aggregate spending refers to the total spending on goods and services in an economy. When aggregate spending decreases, it means that consumers and businesses are spending less, which can lead to a decrease in production, increase in unemployment, and overall economic downturn. This is typically referred to as a recession.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If MPC is 0.7 while government expenditure increased by ₦150m, the equilibrium national income is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦214 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦45 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦105 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦500 million</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1 - MPC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1 - 0.7</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.33</td></tr></table></div>  <br/>  Y = K x Δ G  <br/>     = 3.33 × 150  <br/>  = 500m</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of money which makes division of labour possible is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unit of account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">store of value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium of exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard of deferred payment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Money serves as a medium of exchange in an economy, which makes division of labour possible. Division of labour refers to the splitting up of a task into a number of smaller, more specialized tasks, each of which is undertaken by a different worker or group of workers. Money, as a medium of exchange, allows these workers to trade their specialized services or goods with others, facilitating the division of labour.</div>", "topic": "MONEY : FUNCTIONS OF MONEY"}, {"id": "objective>Economics>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By buying treasury bills, the Central Bank of Nigeria intends to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase money supply in the economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the cash reserve ratio for banks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce money supply in the economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the capital base of commercial banks. </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">By buying treasury bills, the Central Bank of Nigeria intends to reduce money supply in the economy. Treasury bills are short-term debt instruments issued by the government through the central bank to provide short term funding for the government. When the central bank buys these bills, it is essentially taking money out of the economy, thus reducing the money supply.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity of money is represented as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Money supply<hr size=\"1\" />Real GDP</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Real GDP <hr size=\"1\" />Money supply</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Nominal GDP<hr size=\"1\" />Money supply</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">real GDP<hr size=\"1\" />nominal GDP</td></tr></table></div></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">he velocity of money is represented as the ratio of nominal GDP to the money supply. It is a measure of how quickly money is circulating in an economy. <br/>  <br/> Velocity of money = Nominal GDP / Money supply <br/>  <br/> Nominal GDP is the total value of all goods and services produced in an economy in a given period of time, measured in current prices. The money supply is the total amount of money in circulation in an economy, including currency and deposits.</div>", "topic": "MONEY : SUPPLY OF MONEY"}, {"id": "objective>Economics>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of commercial banks is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintaining stable price in the economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">regulating monetary policies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">granting loans to customers   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">issuing bank notes and coins</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial banks are financial institutions that accept deposits from the public, create credit, and grant loans to customers. They do not maintain stable prices in the economy, regulate monetary policies, or issue bank notes and coins. These functions are typically performed by a central bank or a government body.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> A strategy for curbing unemployment is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">implement government stabilization policy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase taxes and decrease government expenditure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase government expenditure and decrease taxes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure even distribution of job opportunities.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increasing government expenditure and decreasing taxes is a strategy for curbing unemployment. This is because when the government spends more on public projects, it creates more jobs. Additionally, when taxes are decreased, businesses have more money to invest and expand, which can lead to more job creation. Implementing government stabilization policy, increasing taxes and decreasing government expenditure, and ensuring even distribution of job opportunities are not direct strategies for curbing unemployment.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> In Nigeria, the huge public debt is as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balanced budgeting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit budgeting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surplus budgeting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero budgeting</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the huge public debt is as a result of deficit budgeting. Deficit budgeting occurs when government's expenditures exceed its revenues, excluding money from borrowings. Deficit spending creates a shortfall that needs to be borrowed, and this borrowing leads to public debt.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">National development plans in Nigeria fail mainly because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overdependence on foreign aids  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate funding of projects </div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor implementation strategies  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of skilled manpower</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Most of Nigeria's development plans are adequate and robust but problem lies in the implementation strategies.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ultimate aim of agricultural policies in Nigeria is to achieve </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food sufficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">full employment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial capacity utilization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The policy goal of NAFPP was to make Nigeria self-sufficient in food production. Consequently, land reform and mass literacy policies were recommended for farmers. OFN was initiated by another regime.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}, {"id": "objective>Economics>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government can boost agricultural output in Nigeria primarily by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> embarking on buffer stock programmes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">placing embargo on food importation </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> granting subsidies on farm inputs </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> placing farmers on monthly income.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Granting of subsidy is a government policy aimed at reducing the selling price of commodity. Subsidy granted on farm input will help to reduce the production cost of farmers.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industries refers to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spread of firms producing different products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">siting of industries near the market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentration of firms of an industry </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> siting of firms producing different products.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industries refers to the concentration of firms of an industry in a specific geographical area. This is often due to factors such as availability of raw materials, skilled labor, infrastructure, and favorable government policies. It does not refer to the spread of firms producing different products, the siting of industries near the market, or the siting of firms producing different products.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In developing countries, government influence the location of industries in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spread development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redistribute wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage entrepreneurs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage industries to earn high profits</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government participate in the location of industries in order to : <br/> - to raise the standard of living <br/> - provision of standard goods <br/> - provision of employment opportunites <br/> - political consideration <br/> - equitable spread of development <br/> - for economic development.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A disadvantage of Nigeria's dependence on imported petroleum products is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">instability in the demand for the products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dominance of multinational firms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">instability in the supply of the product </div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor maintenance of the refineries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's dependence on imported petroleum products leads to instability in the supply of the product. This is because the supply is subject to international market conditions, geopolitical issues, and other factors beyond Nigeria's control. This can lead to fluctuations in availability and price, which can have significant economic impacts.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of shareholders for a limited liability company is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">twenty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seven</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A limited liability company (LLC) can have an unlimited number of shareholders. This is one of the features that distinguish it from other types of business entities. The shareholders of an LLC are not personally liable for the company's debts or liabilities, and there is no maximum limit to the number of shareholders that an LLC can have.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary motive for an individual engaging in production is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">satisfy basic human wants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redistribute wealth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">put inputs into use.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary motive for an individual engaging in production is to make a profit. This is because profit serves as a reward for the risks taken by the individual in the production process. It is the return on investment that motivates an individual to engage in production.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the table below to answer the question that follows </p>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Year</td><td style=\"border:1px solid black;text-align:center;\"> Population (000)</td><td style=\"border:1px solid black;text-align:center;\"> Working Population (000) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2000</td><td style=\"border:1px solid black;text-align:center;\"> 25</td><td style=\"border:1px solid black;text-align:center;\">  13 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2001</td><td style=\"border:1px solid black;text-align:center;\"> 30</td><td style=\"border:1px solid black;text-align:center;\">  19 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2002</td><td style=\"border:1px solid black;text-align:center;\"> 40</td><td style=\"border:1px solid black;text-align:center;\">  32 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2003</td><td style=\"border:1px solid black;text-align:center;\"> 60</td><td style=\"border:1px solid black;text-align:center;\">  49</td></tr></table></div> <br/>  <br/> What is the population growth rate in 2003? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">33.3% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.0% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0% </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The population growth rate is calculated by subtracting the population of the previous year from the population of the current year, dividing the result by the population of the previous year, and then multiplying by 100 to get a percentage. In 2003, the population was 60,000 and in 2002, it was 40,000. Therefore, the population growth rate in 2003 is ((60,000 - 40,000) / 40,000) * 100 = 50%.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the table below to answer the question that follows </p>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Year</td><td style=\"border:1px solid black;text-align:center;\"> Population (000)</td><td style=\"border:1px solid black;text-align:center;\"> Working Population (000) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2000</td><td style=\"border:1px solid black;text-align:center;\"> 25</td><td style=\"border:1px solid black;text-align:center;\">  13 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2001</td><td style=\"border:1px solid black;text-align:center;\"> 30</td><td style=\"border:1px solid black;text-align:center;\">  19 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2002</td><td style=\"border:1px solid black;text-align:center;\"> 40</td><td style=\"border:1px solid black;text-align:center;\">  32 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2003</td><td style=\"border:1px solid black;text-align:center;\"> 60</td><td style=\"border:1px solid black;text-align:center;\">  49</td></tr></table></div> <br/> The percentage of working population in 2002 is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50%  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8%  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">80%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The percentage of working population in 2002 can be calculated by dividing the working population by the total population and then multiplying by 100. From the table, the working population in 2002 is 32,000 and the total population is 40,000. Therefore, the percentage of working population is (32,000/40,000)*100 = 80%. Hence, the correct option is 4.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of free trade zone is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">common tariff against non-member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">different trade policies of non-member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">free factor mobility within the zone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmonized trade among member countries.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A free trade zone is a designated area where goods can be imported, stored, processed and re-exported with minimal regulatory controls. One of the key characteristics of a free trade zone is free factor mobility within the zone. This means that resources such as labor, capital, and goods can move freely within the zone without any restrictions. </div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If Nigeria imports vehicles from Japan, the transaction will appear as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit on Japan's balance of payments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit on Japan's balance of payments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit on Nigeria's balance of trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit on Nigeria's balance of payments.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Nigeria imports vehicles from Japan, it means Nigeria is buying goods from Japan. This transaction will appear as a credit on Japan's balance of payments because it is an inflow of money into Japan. The balance of payments is a record of all economic transactions between the residents of a country and the rest of the world in a particular period. It represents a summation of country's current demand and supply of the claims on foreign currencies and of foreign claims on its currency.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the objectives of ADB is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide subsidies on imported goods to member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilize short-term loans for member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote economic and social development of member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide technical assistance to only poor member countries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Promotion of economic and social development is one of the objectives of ADB (Africa Development Bank).</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The choice of the method of production in an economy is determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">level of income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of technical know-how </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of population growth  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of natural resources.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The method of production has to do with process and techniques that are used to manufacture a product. For an economy that is embracing technological  changes and developments,  the technical-know-how will greatly influence the production technique.</div>", "topic": "THEORY OF PRODUCTION (1) : INTRODUCTION"}, {"id": "objective>Economics>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of labour hired depends on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of skilled labour available </div>", "<div style=\"font-family:Cambria;font-size:17px;\">skill of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal productivity of labour  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of other inputs. </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marginal productivity of labour is defined as the change in total output resulting from employing additional unit of labour.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}];
